//! This module provides consolidated Axum route configuration using backbone-core's
//! BackboneCrudHandler for all 12 standard Backbone CRUD endpoints per entity.

use axum::Router;
use std::sync::Arc;

use super::{
    ad_performance_handler::create_ad_performance_routes,
    advertisement_handler::create_advertisement_routes,
    provider_promo_handler::create_provider_promo_routes,
    promo_campaign_handler::create_promo_campaign_routes,
};

use crate::application::service::{
    AdPerformanceService,
    AdvertisementService,
    ProviderPromoService,
    PromoCampaignService,
};

/// Services collection for all CRUD endpoints
pub struct HttpServices {
    pub ad_performance: Arc<AdPerformanceService>,
    pub advertisement: Arc<AdvertisementService>,
    pub provider_promo: Arc<ProviderPromoService>,
    pub promo_campaign: Arc<PromoCampaignService>,
}

/// Configure all HTTP routes for this module using Axum and BackboneCrudHandler.
///
/// Each entity gets 12 standard Backbone CRUD endpoints:
/// 1. GET /api/v1/{collection} - List with pagination
/// 2. POST /api/v1/{collection} - Create
/// 3. GET /api/v1/{collection}/:id - Get by ID
/// 4. PUT /api/v1/{collection}/:id - Full update
/// 5. PATCH /api/v1/{collection}/:id - Partial update
/// 6. DELETE /api/v1/{collection}/:id - Soft delete
/// 7. POST /api/v1/{collection}/bulk - Bulk create
/// 8. POST /api/v1/{collection}/upsert - Upsert
/// 9. GET /api/v1/{collection}/trash - List deleted
/// 10. POST /api/v1/{collection}/:id/restore - Restore
/// 11. DELETE /api/v1/{collection}/empty - Empty trash
/// 12. GET /api/v1/{collection}/:id/deleted - Get deleted by ID
pub fn configure_routes(services: HttpServices) -> Router {
    Router::new()
        // AdPerformance routes (12 Backbone endpoints)
        .merge(create_ad_performance_routes(services.ad_performance))
        // Advertisement routes (12 Backbone endpoints)
        .merge(create_advertisement_routes(services.advertisement))
        // ProviderPromo routes (12 Backbone endpoints)
        .merge(create_provider_promo_routes(services.provider_promo))
        // PromoCampaign routes (12 Backbone endpoints)
        .merge(create_promo_campaign_routes(services.promo_campaign))
}

/// Create an individual entity's routes (for modular configuration)
pub mod individual {
    use super::*;

    pub fn ad_performance_routes(service: Arc<AdPerformanceService>) -> Router {
        create_ad_performance_routes(service)
    }

    pub fn advertisement_routes(service: Arc<AdvertisementService>) -> Router {
        create_advertisement_routes(service)
    }

    pub fn provider_promo_routes(service: Arc<ProviderPromoService>) -> Router {
        create_provider_promo_routes(service)
    }

    pub fn promo_campaign_routes(service: Arc<PromoCampaignService>) -> Router {
        create_promo_campaign_routes(service)
    }

}
